def convolution(pmf1, pmf2):
    """
    Compute convolution of two probability mass functions.
    pmf1, pmf2 are dictionaries {value: probability}
    Returns {sum_value: probability}
    """
    result = {}
    for v1, p1 in pmf1.items():
        for v2, p2 in pmf2.items():
            s = v1 + v2
            result[s] = result.get(s, 0) + p1 * p2
    return result

# PMF of single die: values 1-6, each with probability 1/6
die_pmf = {i: 1/6 for i in range(1, 7)}

# Convolve twice to get sum of two dice
sum_two_dice = convolution(die_pmf, die_pmf)

# Print results
print("Sum | Probability")
print("-" * 20)
for s in sorted(sum_two_dice.keys()):
    print(f"  {s:2d} | {sum_two_dice[s]:.4f}")

# Verify total probability = 1
print(f"\nTotal probability: {sum(sum_two_dice.values()):.4f}")
print(f"P(sum=7): {sum_two_dice[7]:.4f}")
